const updateOption = (name: string, value: string) => {
  const params = new URLSearchParams(searchParams.toString());
  params.set(name, value);
  router.replace(`?${params.toString()}`, { scroll: false });
};

if (request.nextUrl.basePath) {
  url = new URL(url);
  url.pathname = applyBasePath(url.pathname, request.nextUrl.basePath);
}

const symbolError = Symbol.for('NextjsError')

export function getErrorSource(error: Error): 'server' | 'edge-server' | null {
  return (error as any)[symbolError] || null
}

import { revalidate } from "lib/shopify";
import { NextRequest, NextResponse } from "next/server";

export async function POST(req: NextRequest): Promise<NextResponse> {
  return revalidate(req);
}

async function CollectionList() {
  const collections = await getCollections();
  return <FilterList list={collections} title="Collections" />;
}

export const errorConversionMiddleware = middleware(async ({ next }) => {
  try {
    return await next();
  } catch (e) {
    throw convertErrorWithCodeToTRPCError(e);
  }
});

const hasKeyInMetadata = <T extends string>(
  x: { metadata: unknown } | null,
  key: T
): x is { metadata: { [key in T]: string | boolean | number } } =>
  isPrismaObj(x?.metadata) && !!x?.metadata && key in x.metadata;

export default hasKeyInMetadata;

export const serverFeatureFlags = (userId?: string) => {
  const serverConfig = getServerFeatureFlagsValue();

  return mapFeatureFlagsEnvToState(serverConfig, userId);
};

export const getServerFeatureFlagsValue = () => {
  const flags = parseFeatureFlag(env.FEATURE_FLAGS);

  const result = merge(DEFAULT_FEATURE_FLAGS, flags);
  return result;
};

export function getStableNavigate(): NavigateFunction | null {
  return useGlobalStore.getState().navigationRef.current;
}

export function wrapNormalizerFn(fn: (pathname: string) => string): Normalizer {
  return { normalize: fn }
}
